-- Normalized (3NF): orders reference customers by id, no duplicated customer data
CREATE TABLE customers (
  id          BIGSERIAL PRIMARY KEY,
  email       CITEXT UNIQUE NOT NULL,
  name        TEXT NOT NULL
);

CREATE TABLE orders (
  id          BIGSERIAL PRIMARY KEY,
  customer_id BIGINT NOT NULL REFERENCES customers(id),
  status      TEXT NOT NULL,
  total_cents BIGINT NOT NULL,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Query: latest open orders for a customer, only need id + total
SELECT id, total_cents FROM orders
WHERE customer_id = 42 AND status = 'open'
ORDER BY created_at DESC;

-- Covering composite index. Key columns drive the seek + sort;
-- INCLUDE carries the payload so no heap fetch is needed.
CREATE INDEX idx_orders_cust_status_created
  ON orders (customer_id, status, created_at DESC)
  INCLUDE (total_cents);

BEGIN;
  UPDATE accounts SET balance = balance - 100 WHERE id = 1;
  UPDATE accounts SET balance = balance + 100 WHERE id = 2;
  -- A CHECK (balance >= 0) constraint enforces the invariant.
  -- If the second UPDATE fails, the first is rolled back atomically.
COMMIT;

// N+1: 1 query for orders, then 1 per order for its customer
const orders = await orderRepo.find({ where: { status: 'open' } });
for (const o of orders) {
  o.customer = await customerRepo.findOne({ where: { id: o.customerId } }); // N queries
}

// Fixed: eager-load with a JOIN (one round trip)
const orders = await orderRepo.find({
  where: { status: 'open' },
  relations: { customer: true },   // emits a single JOIN
});
