// TypeScript + node-postgres. Atomic updates + deterministic lock order.
import { Pool, PoolClient } from 'pg';
const pool = new Pool();

async function transfer(fromId: number, toId: number, amount: number) {
  if (amount <= 0) throw new Error('amount must be positive');

  for (let attempt = 0; attempt < 3; attempt++) {
    const client: PoolClient = await pool.connect();
    try {
      await client.query('BEGIN');

      // Lock both rows in a DETERMINISTIC order (ascending id) so that
      // an A->B transfer and a concurrent B->A transfer acquire row
      // locks in the same order and cannot form a deadlock cycle.
      const [first, second] = [fromId, toId].sort((a, b) => a - b);
      await client.query('SELECT id FROM accounts WHERE id = ANY($1) ORDER BY id FOR UPDATE', [[first, second]]);

      // Atomic debit with a non-negative guard. The guard is in the
      // WHERE clause so it is evaluated against the locked, current value;
      // it cannot be raced by another transaction.
      const debit = await client.query(
        'UPDATE accounts SET balance = balance - $1 WHERE id = $2 AND balance >= $1',
        [amount, fromId]
      );
      if (debit.rowCount === 0) {
        await client.query('ROLLBACK');
        throw new Error('insufficient funds');
      }

      await client.query('UPDATE accounts SET balance = balance + $1 WHERE id = $2', [amount, toId]);
      await client.query('COMMIT');
      return;
    } catch (err: any) {
      await client.query('ROLLBACK').catch(() => {});
      // 40P01 deadlock, 40001 serialization failure -> retry
      if ((err.code === '40P01' || err.code === '40001') && attempt < 2) continue;
      throw err;
    } finally {
      client.release();
    }
  }
  throw new Error('transfer failed after retries');
}
